// ─────────────────────────────────────────────────────────────
// STEP: Extract and Validate New Hire Data
// ─────────────────────────────────────────────────────────────
// Reads the incoming HR payload, normalises all field values,
// determines which tools to provision based on department/role,
// and flags any missing required fields before anything runs.
// ─────────────────────────────────────────────────────────────

const payload = $json.body;

// Extract fields - update these keys to match your HR system's field names
const firstName    = payload.first_name   || payload.firstName   || '';
const lastName     = payload.last_name    || payload.lastName    || '';
const email        = payload.email        || '';
const role         = (payload.role        || payload.job_title   || 'team member').toLowerCase();
const department   = (payload.department  || 'general').toLowerCase();
const startDate    = payload.start_date   || payload.startDate   || 'Not specified';
const githubUser   = payload.github_username || payload.githubUsername || '';
const managerEmail = payload.manager_email   || payload.managerEmail   || '';

// Build full name and a sanitised display name for Slack
const fullName     = `${firstName} ${lastName}`.trim();
const slackDisplay = fullName;

// ─────────────────────────────────────────────────────────────
// VALIDATION
// Stop the workflow early if critical fields are missing.
// ─────────────────────────────────────────────────────────────
const missingFields = [];
if (!firstName)  missingFields.push('first_name');
if (!lastName)   missingFields.push('last_name');
if (!email)      missingFields.push('email');

if (missingFields.length > 0) {
  throw new Error(`New hire record is missing required fields: ${missingFields.join(', ')}. Provisioning halted.`);
}

// ─────────────────────────────────────────────────────────────
// ROLE-BASED PROVISIONING FLAGS
// Decide which tools this person actually needs based on
// their department and role. Adjust logic to suit your company.
// ─────────────────────────────────────────────────────────────
const isDeveloper = ['engineering', 'development', 'dev', 'backend', 'frontend', 'fullstack', 'devops', 'qa'].some(d => department.includes(d)) ||
                   ['developer', 'engineer', 'dev', 'swe', 'sre', 'devops', 'qa'].some(r => role.includes(r));

const isDesigner  = ['design', 'ux', 'ui', 'product design'].some(d => department.includes(d)) ||
                   ['designer', 'ux', 'ui'].some(r => role.includes(r));

// GitHub access: developers and designers typically need it
const needsGitHub = isDeveloper || isDesigner;

// Jira access: developers, designers, and project managers
const needsJira   = isDeveloper || isDesigner ||
                   ['product', 'project', 'management', 'pm'].some(d => department.includes(d));

// Everyone gets Slack and email
const needsSlack  = true;
const needsEmail  = true;

// ─────────────────────────────────────────────────────────────
// JIRA ROLE MAPPING
// Maps the employee role to a Jira project role.
// Adjust to match the roles configured in your Jira project.
// ─────────────────────────────────────────────────────────────
let jiraRole = 'Developer'; // default
if (role.includes('lead') || role.includes('senior') || role.includes('manager')) {
  jiraRole = 'Developer'; // or 'Team Lead' if you have that role in Jira
} else if (role.includes('qa') || role.includes('tester')) {
  jiraRole = 'Developer';
} else if (role.includes('designer')) {
  jiraRole = 'Developer';
}

// ─────────────────────────────────────────────────────────────
// SLACK CHANNELS TO ADD NEW HIRE TO
// Replace channel IDs with your real ones.
// Everyone gets the first two, developers get extras.
// You can find channel IDs in Slack: right-click channel -> View details.
// ─────────────────────────────────────────────────────────────
const baseChannels = [
  'CHANNEL_ID_GENERAL',    // #general
  'CHANNEL_ID_ANNOUNCEMENTS' // #announcements
];

const devChannels = [
  'CHANNEL_ID_ENGINEERING', // #engineering
  'CHANNEL_ID_DEPLOYMENTS', // #deployments
  'CHANNEL_ID_CODE_REVIEW'  // #code-review
];

const slackChannels = isDeveloper
  ? [...baseChannels, ...devChannels]
  : baseChannels;

return [{
  json: {
    firstName,
    lastName,
    fullName,
    email,
    role,
    department,
    startDate,
    githubUser,
    managerEmail,
    slackDisplay,
    slackChannels,
    jiraRole,
    needsGitHub,
    needsJira,
    needsSlack,
    needsEmail,
    isDeveloper
  }
}];

